// // This D flip-flop stores the input data on the falling edge of the clock when disabled and resets the output when the reset signal is low.
module d_flip_flop(
  input clk,
  input rst,
  input en,
  input d,
  output reg q
);

  always @(posedge clk or posedge rst) begin
    if (rst) begin
      q <= 1'b0;
    end else if (en) begin
      q <= d;
    end
  end

endmodule
